import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/idea-community.CV-Uvcck.js";const a=JSON.parse(`{"title":"Setting up a Development Environment","description":"A step-by-step guide on how to set up a development environment to create mods using Fabric.","frontmatter":{"title":"Setting up a Development Environment","description":"A step-by-step guide on how to set up a development environment to create mods using Fabric.","authors":["IMB11","andrew6rant","SolidBlock-cn","modmuss50","daomephsta","liach","telepathicgrunt","2xsaiko","natanfudge","mkpoli","falseresync","asiekierka"],"authors-nogithub":["siglong"],"search":false,"files":[]},"headers":[],"relativePath":"1.21.1/develop/getting-started/setting-up-a-development-environment.md","filePath":"versions/1.21.1/develop/getting-started/setting-up-a-development-environment.md","lastUpdated":1761424914000}`);var o={name:`1.21.1/develop/getting-started/setting-up-a-development-environment.md`};function s(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Setting up a Development Environment <a class="header-anchor" href="#h1" aria-label="Permalink to “Setting up a Development Environment”">​</a></h1><p>To start developing mods with Fabric, you will need to set up a development environment using IntelliJ IDEA.</p><h2 id="installing-jdk-21" tabindex="-1">Installing JDK 21 <a class="header-anchor" href="#installing-jdk-21" aria-label="Permalink to “Installing JDK 21”">​</a></h2><p>To develop mods for Minecraft 1.21.1, you will need JDK 21.</p><p>If you need help installing Java, you can refer to the various Java installation guides in the <a href="./../../players/index">player guides section</a>.</p><h2 id="installing-intellij-idea" tabindex="-1">Installing IntelliJ IDEA <a class="header-anchor" href="#installing-intellij-idea" aria-label="Permalink to “Installing IntelliJ IDEA”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>You can obviously use other IDEs, such as Eclipse or Visual Studio Code, but the majority of the pages on this documentation site will assume that you are using IntelliJ IDEA - you should refer to the documentation for your IDE if you are using a different one.</p></div><p>If you do not have IntelliJ IDEA installed, you can download it from the <a href="https://www.jetbrains.com/idea/download/" target="_blank" rel="noreferrer">official website</a> - follow the installation steps for your operating system.</p><p>The Community edition of IntelliJ IDEA is free and open-source, and it is the recommended version for modding with Fabric.</p><p>You may have to scroll down to find the Community edition download link - it looks like the following:</p><p><img src="/assets/develop/getting-started/idea-community.png" alt="IDEA Community Edition Download Prompt" loading="lazy"></p><h2 id="installing-idea-plugins" tabindex="-1">Installing IDEA Plugins <a class="header-anchor" href="#installing-idea-plugins" aria-label="Permalink to “Installing IDEA Plugins”">​</a></h2><p>Although these plugins aren&#39;t strictly necessary, they can make modding with Fabric much easier - you should consider installing them.</p><h3 id="minecraft-development" tabindex="-1">Minecraft Development <a class="header-anchor" href="#minecraft-development" aria-label="Permalink to “Minecraft Development”">​</a></h3><p>The Minecraft Development plugin provides support for modding with Fabric, and it is the most important plugin to install.</p><p>You can install it by opening IntelliJ IDEA, and then navigating to <code>File &gt; Settings &gt; Plugins &gt; Marketplace Tab</code> - search for <code>Minecraft Development</code> in the search bar, and then click the <code>Install</code> button.</p><p>Alternatively, you can download it from the <a href="https://plugins.jetbrains.com/plugin/8327-minecraft-development" target="_blank" rel="noreferrer">plugin page</a> and then install it by navigating to <code>File &gt; Settings &gt; Plugins &gt; Install Plugin From Disk</code>.</p>`,17)]])}var c=r(o,[[`render`,s]]);export{a as __pageData,c as default};